import sys

def search_insert_position(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return left

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        target = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out.append(str(search_insert_position(arr, target)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

